+/**
+ * HOLOGRAPHIC THEME EFFECTS
+ * Mind-blowing glassmorphism, holographic gradients, and animated effects
+ */
+
+/* =============================================================================
+   ANIMATED HOLOGRAPHIC BACKGROUND
+   Subtle moving gradient that creates depth and visual interest
+   ============================================================================= */
+
+@keyframes holographic-shift {
+  0%, 100% {
+    background-position: 0% 50%;
+  }
+  50% {
+    background-position: 100% 50%;
+  }
+}
+
+@keyframes holographic-pulse {
+  0%, 100% {
+    opacity: 0.3;
+  }
+  50% {
+    opacity: 0.5;
+  }
+}
+
+@keyframes border-glow {
+  0%, 100% {
+    box-shadow:
+      0 0 5px rgba(0, 245, 255, 0.3),
+      0 0 10px rgba(191, 0, 255, 0.2),
+      inset 0 0 20px rgba(0, 245, 255, 0.05);
+  }
+  50% {
+    box-shadow:
+      0 0 10px rgba(0, 245, 255, 0.5),
+      0 0 20px rgba(191, 0, 255, 0.3),
+      inset 0 0 30px rgba(0, 245, 255, 0.08);
+  }
+}
+
+@keyframes shimmer {
+  0% {
+    background-position: -200% 0;
+  }
+  100% {
+    background-position: 200% 0;
+  }
+}
+
+/* =============================================================================
+   HOLOGRAPHIC THEME SPECIFIC STYLES
+   Applied when data-theme="holographic"
+   ============================================================================= */
+
+[data-theme="holographic"] {
+  /* Animated background gradient */
+  --holo-gradient: linear-gradient(
+    135deg,
+    rgba(191, 0, 255, 0.08) 0%,
+    rgba(0, 245, 255, 0.05) 25%,
+    rgba(255, 0, 110, 0.05) 50%,
+    rgba(0, 245, 255, 0.08) 75%,
+    rgba(191, 0, 255, 0.05) 100%
+  );
+
+  --holo-border-gradient: linear-gradient(
+    135deg,
+    rgba(0, 245, 255, 0.6) 0%,
+    rgba(191, 0, 255, 0.6) 50%,
+    rgba(255, 0, 110, 0.6) 100%
+  );
+
+  --glass-bg: rgba(3, 0, 20, 0.7);
+  --glass-blur: 20px;
+  --glass-border: rgba(255, 255, 255, 0.08);
+}
+
+/* Main app background with animated gradient */
+[data-theme="holographic"] .app-shell {
+  background:
+    radial-gradient(ellipse at 20% 0%, rgba(191, 0, 255, 0.15) 0%, transparent 50%),
+    radial-gradient(ellipse at 80% 100%, rgba(0, 245, 255, 0.12) 0%, transparent 50%),
+    radial-gradient(ellipse at 40% 60%, rgba(255, 0, 110, 0.08) 0%, transparent 40%),
+    linear-gradient(180deg, #030014 0%, #050020 50%, #030014 100%);
+  background-size: 200% 200%, 200% 200%, 100% 100%, 100% 100%;
+  animation: holographic-shift 20s ease infinite;
+}
+
+/* =============================================================================
+   GLASSMORPHIC PANELS
+   Frosted glass effect with backdrop blur
+   ============================================================================= */
+
+[data-theme="holographic"] .panel,
+[data-theme="holographic"] .detail-card {
+  background: rgba(5, 0, 30, 0.6);
+  backdrop-filter: blur(20px);
+  -webkit-backdrop-filter: blur(20px);
+  border: 1px solid rgba(255, 255, 255, 0.08);
+  box-shadow:
+    0 8px 32px rgba(0, 0, 0, 0.4),
+    0 0 0 1px rgba(191, 0, 255, 0.1),
+    inset 0 0 60px rgba(0, 245, 255, 0.03);
+  position: relative;
+  overflow: hidden;
+}
+
+/* Holographic shimmer overlay on panels */
+[data-theme="holographic"] .panel::before,
+[data-theme="holographic"] .detail-card::before {
+  content: '';
+  position: absolute;
+  top: 0;
+  left: 0;
+  right: 0;
+  height: 1px;
+  background: linear-gradient(
+    90deg,
+    transparent 0%,
+    rgba(0, 245, 255, 0.5) 20%,
+    rgba(191, 0, 255, 0.5) 50%,
+    rgba(255, 0, 110, 0.5) 80%,
+    transparent 100%
+  );
+  opacity: 0.6;
+}
+
+/* =============================================================================
+   GLASSMORPHIC HEADER
+   ============================================================================= */
+
+[data-theme="holographic"] .app-header {
+  background: rgba(3, 0, 20, 0.85);
+  backdrop-filter: blur(20px);
+  -webkit-backdrop-filter: blur(20px);
+  border-bottom: 1px solid rgba(191, 0, 255, 0.2);
+  box-shadow:
+    0 4px 30px rgba(0, 0, 0, 0.3),
+    0 0 40px rgba(191, 0, 255, 0.05);
+}
+
+/* =============================================================================
+   GLASSMORPHIC DATABASE STATUS BAR
+   ============================================================================= */
+
+[data-theme="holographic"] .db-status-bar {
+  background: rgba(5, 0, 30, 0.5);
+  backdrop-filter: blur(16px);
+  -webkit-backdrop-filter: blur(16px);
+  border: 1px solid rgba(0, 245, 255, 0.15);
+  box-shadow:
+    0 4px 20px rgba(0, 0, 0, 0.3),
+    inset 0 0 30px rgba(0, 245, 255, 0.02);
+}
+
+[data-theme="holographic"] .db-status-icon {
+  color: #00ffa3;
+  text-shadow: 0 0 10px rgba(0, 255, 163, 0.5);
+}
+
+/* =============================================================================
+   HOLOGRAPHIC LIST ITEMS
+   ============================================================================= */
+
+[data-theme="holographic"] .list-item {
+  background: rgba(5, 0, 30, 0.3);
+  border: 1px solid rgba(255, 255, 255, 0.05);
+  transition: all 0.3s ease;
+}
+
+[data-theme="holographic"] .list-item:hover {
+  background: rgba(0, 245, 255, 0.08);
+  border-color: rgba(0, 245, 255, 0.2);
+  box-shadow:
+    0 4px 20px rgba(0, 245, 255, 0.1),
+    inset 0 0 20px rgba(0, 245, 255, 0.03);
+}
+
+[data-theme="holographic"] .list-item.active {
+  background: linear-gradient(
+    135deg,
+    rgba(0, 245, 255, 0.15) 0%,
+    rgba(191, 0, 255, 0.1) 100%
+  );
+  border-color: rgba(0, 245, 255, 0.4);
+  box-shadow:
+    0 0 20px rgba(0, 245, 255, 0.2),
+    0 0 40px rgba(191, 0, 255, 0.1),
+    inset 0 0 30px rgba(0, 245, 255, 0.05);
+  animation: border-glow 3s ease-in-out infinite;
+}
+
+[data-theme="holographic"] .list-item.active::before {
+  background: linear-gradient(180deg, #00f5ff 0%, #bf00ff 100%);
+  box-shadow: 0 0 10px rgba(0, 245, 255, 0.5);
+}
+
+/* =============================================================================
+   HOLOGRAPHIC BUTTONS
+   ============================================================================= */
+
+[data-theme="holographic"] .btn {
+  background: rgba(5, 0, 30, 0.6);
+  backdrop-filter: blur(10px);
+  -webkit-backdrop-filter: blur(10px);
+  border: 1px solid rgba(0, 245, 255, 0.3);
+  color: #00f5ff;
+  transition: all 0.3s ease;
+  position: relative;
+  overflow: hidden;
+}
+
+[data-theme="holographic"] .btn::before {
+  content: '';
+  position: absolute;
+  top: 0;
+  left: -100%;
+  width: 100%;
+  height: 100%;
+  background: linear-gradient(
+    90deg,
+    transparent 0%,
+    rgba(0, 245, 255, 0.2) 50%,
+    transparent 100%
+  );
+  transition: left 0.5s ease;
+}
+
+[data-theme="holographic"] .btn:hover {
+  background: rgba(0, 245, 255, 0.15);
+  border-color: rgba(0, 245, 255, 0.5);
+  box-shadow:
+    0 0 20px rgba(0, 245, 255, 0.3),
+    inset 0 0 20px rgba(0, 245, 255, 0.05);
+  text-shadow: 0 0 10px rgba(0, 245, 255, 0.5);
+}
+
+[data-theme="holographic"] .btn:hover::before {
+  left: 100%;
+}
+
+/* =============================================================================
+   HOLOGRAPHIC BADGES
+   ============================================================================= */
+
+[data-theme="holographic"] .badge {
+  background: linear-gradient(
+    135deg,
+    rgba(0, 245, 255, 0.2) 0%,
+    rgba(191, 0, 255, 0.2) 100%
+  );
+  border: 1px solid rgba(0, 245, 255, 0.3);
+  color: #00f5ff;
+  text-shadow: 0 0 5px rgba(0, 245, 255, 0.3);
+  backdrop-filter: blur(5px);
+  -webkit-backdrop-filter: blur(5px);
+}
+
+[data-theme="holographic"] .badge-info {
+  background: linear-gradient(135deg, rgba(0, 245, 255, 0.2) 0%, rgba(0, 212, 255, 0.2) 100%);
+  border-color: rgba(0, 245, 255, 0.4);
+  color: #00f5ff;
+}
+
+[data-theme="holographic"] .badge-warning {
+  background: linear-gradient(135deg, rgba(255, 170, 0, 0.2) 0%, rgba(255, 136, 0, 0.2) 100%);
+  border-color: rgba(255, 170, 0, 0.4);
+  color: #ffaa00;
+}
+
+/* =============================================================================
+   HOLOGRAPHIC SEQUENCE VIEWER
+   ============================================================================= */
+
+[data-theme="holographic"] .sequence-block {
+  background: rgba(3, 0, 20, 0.8);
+  backdrop-filter: blur(10px);
+  -webkit-backdrop-filter: blur(10px);
+  border: 1px solid rgba(191, 0, 255, 0.2);
+  box-shadow:
+    inset 0 0 60px rgba(0, 0, 0, 0.5),
+    0 4px 20px rgba(0, 0, 0, 0.3);
+}
+
+/* =============================================================================
+   HOLOGRAPHIC 3D VIEWER
+   ============================================================================= */
+
+[data-theme="holographic"] .three-container {
+  border: 1px solid rgba(0, 245, 255, 0.2);
+  box-shadow:
+    0 8px 32px rgba(0, 0, 0, 0.4),
+    0 0 0 1px rgba(191, 0, 255, 0.1),
+    inset 0 0 100px rgba(0, 245, 255, 0.02);
+  background:
+    radial-gradient(ellipse at 30% 20%, rgba(0, 245, 255, 0.1) 0%, transparent 40%),
+    radial-gradient(ellipse at 70% 80%, rgba(191, 0, 255, 0.1) 0%, transparent 40%),
+    rgba(3, 0, 20, 0.9);
+}
+
+/* =============================================================================
+   HOLOGRAPHIC SCROLLBARS
+   ============================================================================= */
+
+[data-theme="holographic"] ::-webkit-scrollbar {
+  width: 8px;
+  height: 8px;
+}
+
+[data-theme="holographic"] ::-webkit-scrollbar-track {
+  background: rgba(3, 0, 20, 0.5);
+  border-radius: 4px;
+}
+
+[data-theme="holographic"] ::-webkit-scrollbar-thumb {
+  background: linear-gradient(180deg, #00f5ff 0%, #bf00ff 100%);
+  border-radius: 4px;
+  border: 1px solid rgba(0, 245, 255, 0.3);
+}
+
+[data-theme="holographic"] ::-webkit-scrollbar-thumb:hover {
+  background: linear-gradient(180deg, #33f7ff 0%, #d633ff 100%);
+  box-shadow: 0 0 10px rgba(0, 245, 255, 0.5);
+}
+
+/* =============================================================================
+   HOLOGRAPHIC TEXT EFFECTS
+   ============================================================================= */
+
+[data-theme="holographic"] .app-title {
+  background: linear-gradient(
+    90deg,
+    #00f5ff 0%,
+    #bf00ff 50%,
+    #00f5ff 100%
+  );
+  background-size: 200% auto;
+  -webkit-background-clip: text;
+  background-clip: text;
+  -webkit-text-fill-color: transparent;
+  animation: shimmer 3s linear infinite;
+}
+
+[data-theme="holographic"] h1,
+[data-theme="holographic"] h2,
+[data-theme="holographic"] h3,
+[data-theme="holographic"] h4 {
+  text-shadow: 0 0 20px rgba(0, 245, 255, 0.2);
+}
+
+/* =============================================================================
+   HOLOGRAPHIC FOCUS STATES
+   ============================================================================= */
+
+[data-theme="holographic"] *:focus-visible {
+  outline: none;
+  box-shadow:
+    0 0 0 2px rgba(0, 245, 255, 0.5),
+    0 0 20px rgba(0, 245, 255, 0.3);
+}
+
+/* =============================================================================
+   HOLOGRAPHIC FOOTER
+   ============================================================================= */
+
+[data-theme="holographic"] .app-footer {
+  background: rgba(3, 0, 20, 0.9);
+  backdrop-filter: blur(10px);
+  -webkit-backdrop-filter: blur(10px);
+  border-top: 1px solid rgba(191, 0, 255, 0.2);
+}
+
+/* =============================================================================
+   REDUCED MOTION
+   Disable animations for users who prefer reduced motion
+   ============================================================================= */
+
+@media (prefers-reduced-motion: reduce) {
+  [data-theme="holographic"] .app-shell {
+    animation: none;
+    background:
+      radial-gradient(ellipse at 20% 0%, rgba(191, 0, 255, 0.15) 0%, transparent 50%),
+      radial-gradient(ellipse at 80% 100%, rgba(0, 245, 255, 0.12) 0%, transparent 50%),
+      #030014;
+  }
+
+  [data-theme="holographic"] .app-title {
+    animation: none;
+    background-position: 0% 0%;
+  }
+
+  [data-theme="holographic"] .list-item.active {
+    animation: none;
+  }
+
+  [data-theme="holographic"] .btn::before {
+    display: none;
+  }
+}
